import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import { LucideIcon } from "lucide-react";

export interface NavItem {
  id: string;
  label: string;
  icon: LucideIcon;
  badge?: string;
  subItems?: NavItem[];
  indent?: boolean;
}

export interface MetricCardProps {
  title: string;
  value: string | number;
  subtext: string;
  icon: LucideIcon;
  variant: 'blue' | 'yellow' | 'green' | 'purple';
}

export interface Vendor {
  id: number;
  name: string;
  amount: number;
}

import React from 'react';
import { 
  LayoutDashboard, 
  UploadCloud, 
  FileCheck2, 
  PieChart, 
  Filter, 
  Download, 
  Bot, 
  ShieldCheck, 
  Settings 
} from 'lucide-react';
import { NavItem } from '../types';

interface SidebarProps {
  activeTab: string;
  setActiveTab: (tab: string) => void;
}

const Sidebar: React.FC<SidebarProps> = ({ activeTab, setActiveTab }) => {
  const navItems: NavItem[] = [
    { id: 'dashboard', label: 'Dashboard', icon: LayoutDashboard },
    { id: 'intake', label: 'Document Intake', icon: UploadCloud },
    { 
      id: 'review', 
      label: 'Review & Categorize', 
      icon: FileCheck2, 
      badge: '2',
      indent: true 
    },
    { id: 'allocation', label: 'Insurance Allocation', icon: PieChart },
    { id: 'filter', label: 'Double-Pull Filter', icon: Filter },
    { id: 'export', label: 'Buildium Export', icon: Download },
    { id: 'qa', label: 'QA Agent', icon: Bot },
    { id: 'audit', label: 'Audit Center', icon: ShieldCheck },
  ];

  return (
    <div className="w-64 bg-white h-screen flex flex-col border-r border-gray-200 fixed left-0 top-0 overflow-y-auto z-10">
      {/* Header */}
      <div className="p-6 flex items-center gap-3">
        <div className="w-8 h-8 bg-indigo-600 rounded flex items-center justify-center text-white font-bold text-lg">
          B
        </div>
        <span className="text-gray-500 text-sm font-medium">Automation System</span>
      </div>

      {/* Navigation */}
      <nav className="flex-1 px-4 space-y-1">
        {navItems.map((item) => (
          <button
            key={item.id}
            onClick={() => setActiveTab(item.id)}
            className={`w-full flex items-center justify-between px-3 py-2.5 rounded-lg text-sm font-medium transition-colors ${
              activeTab === item.id
                ? 'bg-indigo-50 text-indigo-600'
                : 'text-gray-600 hover:bg-gray-50 hover:text-gray-900'
            } ${item.indent ? 'pl-9' : ''}`}
          >
            <div className="flex items-center gap-3">
              {!item.indent && <item.icon size={18} strokeWidth={2} />}
              {/* If indented, use a smaller icon or just text. Image implies specific icon but aligned differently */}
              {item.indent && <item.icon size={16} strokeWidth={2} className={activeTab === item.id ? 'text-indigo-600' : 'text-gray-400'} />}
              <span>{item.label}</span>
            </div>
            {item.badge && (
              <span className="bg-amber-100 text-amber-700 text-xs font-bold px-2 py-0.5 rounded-full">
                {item.badge}
              </span>
            )}
          </button>
        ))}
      </nav>

      {/* Footer */}
      <div className="p-4 border-t border-gray-100">
        <button className="flex items-center gap-3 text-gray-600 hover:text-gray-900 px-3 py-2 w-full text-sm font-medium">
          <Settings size={18} />
          <span>Settings</span>
        </button>
        <div className="mt-4 px-3 text-xs text-gray-400">
          v2.6.0 • Sandbox Env
        </div>
      </div>
    </div>
  );
};

export default Sidebar;

import React from 'react';
import { LucideIcon } from 'lucide-react';
import { MetricCardProps } from '../types';

const StatCard: React.FC<MetricCardProps> = ({ title, value, subtext, icon: Icon, variant }) => {
  const variantStyles = {
    blue: {
      iconBg: 'text-blue-500',
      border: 'border-transparent',
    },
    yellow: {
      iconBg: 'text-amber-500',
      border: 'border-amber-400', // The yellow card has a visible border in the image
    },
    green: {
      iconBg: 'text-emerald-500',
      border: 'border-transparent',
    },
    purple: {
      iconBg: 'text-violet-600',
      border: 'border-transparent',
    }
  };

  const styles = variantStyles[variant];

  return (
    <div className={`bg-white p-5 rounded-lg border shadow-sm flex flex-col justify-between h-32 ${variant === 'yellow' ? 'border-amber-200' : 'border-gray-100'}`}>
      <div className="flex justify-between items-start">
        <span className="text-gray-500 text-xs font-medium uppercase tracking-wide">{title}</span>
        <Icon className={styles.iconBg} size={18} />
      </div>
      <div>
        <div className="text-2xl font-bold text-gray-900">{value}</div>
        <div className="text-xs text-gray-400 mt-1">{subtext}</div>
      </div>
    </div>
  );
};

export default StatCard;

